import { useState } from "react";
import { motion } from "framer-motion";

export default function AdminPanel() {
  const [page, setPage] = useState("dashboard");
  const [foodName, setFoodName] = useState("");
  const [price, setPrice] = useState("");

  const addFood = () => {
    const foods = JSON.parse(localStorage.getItem("foods") || "[]");
    foods.push({ foodName, price });
    localStorage.setItem("foods", JSON.stringify(foods));
    setFoodName("");
    setPrice("");
    alert("Food Added Successfully");
  };

  const Dashboard = () => (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
      <h1 className="text-3xl font-bold mb-6">Admin Dashboard</h1>
      <div className="grid grid-cols-2 gap-4">
        <button className="btn btn-primary" onClick={() => setPage("addFood")}>Add Food</button>
        <button className="btn btn-primary" onClick={() => setPage("viewFoods")}>View Foods</button>
        <button className="btn btn-primary" onClick={() => setPage("orders")}>Orders</button>
        <button className="btn btn-primary" onClick={() => setPage("bookings")}>Bookings</button>
      </div>
    </motion.div>
  );

  const AddFood = () => (
    <motion.div initial={{ x: 100, opacity: 0 }} animate={{ x: 0, opacity: 1 }}>
      <div className="card p-4">
        <div className="card-body">
          <h2 className="card-title">Add Food</h2>
          <input
            type="text"
            className="form-control mb-3"
            placeholder="Food Name"
            value={foodName}
            onChange={(e) => setFoodName(e.target.value)}
          />
          <input
            type="text"
            className="form-control mb-3"
            placeholder="Price"
            value={price}
            onChange={(e) => setPrice(e.target.value)}
          />
          <button className="btn btn-success" onClick={addFood}>Save Food</button>
        </div>
      </div>
    </motion.div>
  );

  const ViewFoods = () => {
    const foods = JSON.parse(localStorage.getItem("foods") || "[]");
    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
        <h2 className="text-2xl mb-4">Food List</h2>
        {foods.map((food, index) => (
          <div key={index} className="card mb-2 p-3">
            {food.foodName} - KES {food.price}
          </div>
        ))}
      </motion.div>
    );
  };

  const Orders = () => (
    <div>
      <h2 className="text-2xl">Orders Page</h2>
      <p>Food orders will appear here.</p>
    </div>
  );

  const Bookings = () => (
    <div>
      <h2 className="text-2xl">Bookings Page</h2>
      <p>Room & Event bookings will appear here.</p>
    </div>
  );

  return (
    <div className="p-6">
      {page === "dashboard" && <Dashboard />}
      {page === "addFood" && <AddFood />}
      {page === "viewFoods" && <ViewFoods />}
      {page === "orders" && <Orders />}
      {page === "bookings" && <Bookings />}
      <button className="btn btn-secondary mt-6" onClick={() => setPage("dashboard")}>
        Back to Dashboard
      </button>
    </div>
  );
}
